DRESULT disk_ioctl (
	BYTE pdrv,		/* Physical drive nmuber (0..) */
	BYTE cmd,		/* Control code */
	void *buff		/* Buffer to send/receive control data */
)
{
    DRESULT res;

    if (pdrv != DEV_MMC){
        return RES_PARERR;
    }

    switch (cmd) {
    case CTRL_SYNC:
        res = RES_OK;
        break;
    case GET_SECTOR_COUNT:
        *(DWORD*)buff = 13631488;
        res = RES_OK;
        break;
    case GET_SECTOR_SIZE:
        *(WORD*)buff = 512;
        res = RES_OK;
        break;
    case GET_BLOCK_SIZE:
        *(WORD*)buff = 4096;
        res = RES_OK;
        break;
//    case CTRL_TRIM:
//        result = sd_trim(spictrl, (LBA_t)buff);
//        res = result == 0 ? RES_OK : RES_ERROR;
//        break;
    default:
        res = RES_PARERR;
        break;
    }

    return res;
