uint64 do_mmap_fix(uint64 start, uint64 len, int flags, int fd, off_t offset)
{
    struct proc* p = myproc();
    map_fix* mf = kmalloc(sizeof(map_fix));
    *mf = (map_fix){
        .addr = start,  //映射起始地址
        .sz = len,
        .flags = flags,
        .fd = fd,
        .f_off = offset,
        .next = p->mf,
        .type = MMAP
    };
    p->mf = mf;
    return 0;
}

uint64 do_mmap(uint64 start, uint64 len, int prot, int flags, int fd, off_t offset)
{
    struct proc *p = myproc();

    if(flags & MAP_ANONYMOUS)
    {
        fd = -1;
        goto ignore_fd;
    }

    if(fd < 0)
    {
        __debug_warn("[do_mmap] fd illegal, fd = %d\n", fd);
        return -1;
    }

    if(fd > NOFILEMAX(p))
    {
        __debug_warn("[do_mmap] fd illegal, fd(%d) > NOFILEMAX(%d)\n", fd, NOFILEMAX(p));
        return -1;
    }

ignore_fd:
    if(offset < 0)
    {
        __debug_warn("[do_mmap] offset illegal, offset = %d\n", offset);
        return -1;
    }
    if(start % PGSIZE != 0)
    {
        __debug_warn("[do_mmap] mmap start address not aligned\n");
        return -1;
    }
    // print_vma_info(p);
    // __debug_info("[dp_mmap] start = %p, len = %p, flags = %p, fd = %d, offset = %d\n", start, len, flags, fd, offset);
    int perm = PTE_U;
    if(prot & PROT_READ) 
        perm  |= (PTE_R | PTE_A);
    if(prot & PROT_WRITE)
        perm  |= (PTE_W | PTE_D);
    if(prot & PROT_EXEC)
        perm  |= (PTE_X | PTE_A);

    struct file *f = fd == -1 ? NULL : p->ofile[fd];
    if(fd != -1 && f == NULL)
    {
        __debug_warn("[do_mmap] mmap file illegal\n");
        return -1;
    }

    if((flags & MAP_FIXED) && start != 0)
    {
        do_mmap_fix(start, len, flags, fd, offset);
        goto skip_vma;
    }

    struct vma *vma = alloc_mmap_vma(p, flags, start, len, perm, fd, offset);
    start = vma->addr;
    if(vma == NULL)
    {
        __debug_warn("[do_mmap] alloc mmap vma failed\n");
        return -1;
    }

    uint64 mmap_sz ;
skip_vma:
    mmap_sz = 0;
    if(fd != -1)
    {
        mmap_sz = f->ep->file_size - offset;
        if(len < mmap_sz)
            mmap_sz = len;
        f->off = offset;
    }
    else
    {
        return start;
    }

    // read and copy file to memory
    uint64 end_pagespace = mmap_sz % PGSIZE;
    int page_n = PGROUNDUP(mmap_sz) >> PGSHIFT;
    uint64 va = start;

    for(int i = 0; i < page_n; ++i)
    {
        uint64 pa = experm(p->pagetable, va, perm);
        if(pa == NULL)
        {
            __debug_warn("[do_mmap] va = %p, pa not found\n", va);
            return -1;
        }
        if(i != page_n - 1)
        {
            fileread(f, va, PGSIZE);
        }
        else 
        {
            fileread(f, va, end_pagespace);
            memset((void *)(pa + end_pagespace), 0, PGSIZE - end_pagespace);
        }
        va += PGSIZE;
    }

    filedup(f);
    return start;
}

map_fix* do_munmap_fix(struct proc* p,uint64 start, uint64 len){
    map_fix* i = p->mf;
    map_fix* last = NULL;
    while(i){
        if(i->addr==start&&i->sz == len){
            goto success;
        }
        last = i;
        i = i->next;
    }
    return NULL;
success:
    if(last)last->next = i->next;
    else p->mf = i->next;
    return i;
}

uint64 do_munmap(struct proc* np,uint64 start, uint64 len)
{
    struct proc *p = np?np:myproc();
    map_fix* mf = do_munmap_fix(p,start,len);
    struct vma *vma = mf?mf:addr_sz_locate_vma(p->vma, start, len);

    if(vma == NULL || vma->type != MMAP)
    {
        __debug_warn("[do_munmap] munmap address/sz illegal\n");
        return -1;
    }

    if(vma->fd == -1||(vma->flags & MAP_PRIVATE))
    {
        goto ignore_wb;
    }

    struct file *f = p->ofile[vma->fd];
    if(f == NULL)
    {
        __debug_warn("[do_munmap] open file not found\n");
        return -1;
    }

    uint64 pa, size, total_size = len;
    uint64 va = start;
    int page_n = (vma->end - vma->addr) >> PGSHIFT;

    f->off = vma->f_off;

    for(int i = 0; i < page_n; ++i)
    {
        size = total_size >= PGSIZE ? PGSIZE : total_size;
        pte_t * pte = walk(p->pagetable, va, 0);

        if((*pte & PTE_V) == 0)
        {
            __debug_warn("[do_munmap] page not valid\n");
            return -1;
        }
        if((*pte & PTE_U) == 0)
        {
            __debug_warn("[do_munmap] page is not user mode\n");
        }
        if(*pte & PTE_D){       // write back when PTE_D bit is 1
            pa = PTE2PA(*pte);
            if(!pa){
                __debug_warn("[do_munmap] page' pa is 0\n");
                return -1;
            }
            filewrite(f, va, size);
        }
        va += PGSIZE;
        total_size -= size;
    }
ignore_wb:
    if(!mf && free_vma(p, vma) == 0)
    {
        __debug_warn("[do_munmap] free vma failed\n");
        return -1;
    }else if(mf){
        kfree(mf);
    }

    return 0;

}

void
free_map_fix(struct proc* p){
    map_fix* mf = p->mf;
	map_fix* i = mf;
    map_fix* next;
    while(i){
        next = i->next;
        do_munmap(p,i->addr,i->sz);
        i = next;
    }
}

int
pipealloc(struct file **f0, struct file **f1)
{
  struct pipe *pi;

  pi = 0;
  *f0 = *f1 = 0;
  if((*f0 = filealloc()) == NULL || (*f1 = filealloc()) == NULL)
    goto bad;
  if((pi = kmalloc(sizeof(struct pipe))) == NULL)
    goto bad;
  pi->readopen = 1;
  pi->writeopen = 1;
  pi->nwrite = 0;
  pi->nread = 0;
  initlock(&pi->lock, "pipe");
  (*f0)->type = FD_PIPE;
  (*f0)->readable = 1;
  (*f0)->writable = 0;
  (*f0)->pipe = pi;
  (*f1)->type = FD_PIPE;
  (*f1)->readable = 0;
  (*f1)->writable = 1;
  (*f1)->pipe = pi;
  return 0;

 bad:
  if(pi)
    kfree((char*)pi);
  if(*f0)
    fileclose(*f0);
  if(*f1)
    fileclose(*f1);
  return -1;
}

void
pipeclose(struct pipe *pi, int writable)
{
  acquire(&pi->lock);
  if(writable){
    pi->writeopen = 0;
    wakeup(&pi->nread);
  } else {
    pi->readopen = 0;
    wakeup(&pi->nwrite);
  }
  if(pi->readopen == 0 && pi->writeopen == 0){
    release(&pi->lock);
    kfree((char*)pi);
  } else
    release(&pi->lock);
}

int
pipewrite(struct pipe *pi, int user, uint64 addr, int n)
{
  int i;
  char ch;
  struct proc *pr = myproc();

  printf("[pipe]nread %d nwrite %d n %p\n", pi->nread, pi->nwrite, n);
  for(i = 0; i < n; i++){
    while(pi->nwrite == pi->nread + PIPESIZE){  //DOC: pipewrite-full
      if(pi->readopen == 0 || pr->killed){
        release(&pi->lock);
        return -1;
      }
      wakeup(&pi->nread);
      sleep(&pi->nwrite, &pi->lock);
    }
    // if(copyin(pr->pagetable, &ch, addr + i, 1) == -1)
    if(either_copyin(user,&ch, addr + i, 1) == -1)
      break;
    pi->data[pi->nwrite++ % PIPESIZE] = ch;
  }
  wakeup(&pi->nread);
  return i;
}

int
piperead(struct pipe *pi, int user, uint64 addr, int n)
{
  int i;
  struct proc *pr = myproc();
  char ch;

  while(pi->nread == pi->nwrite && pi->writeopen){  //DOC: pipe-empty
    if(pr->killed){
      release(&pi->lock);
      return -1;
    }
    sleep(&pi->nread, &pi->lock); //DOC: piperead-sleep
  }
  for(i = 0; i < n; i++){  //DOC: piperead-copy

    if(pi->nread == pi->nwrite)
      break;
    ch = pi->data[pi->nread++ % PIPESIZE];
    // if(copyout(pr->pagetable, addr + i, &ch, 1) == -1)
    if(either_copyout(user, addr + i, &ch, 1) == -1)
      break;
  }
  wakeup(&pi->nwrite);  //DOC: piperead-wakeup
  return i;
}

static void
freerange(void *pa_start, void *pa_end)
{
	char *p;
	p = (char*)PGROUNDUP((uint64)pa_start);
	for(; p + PGSIZE <= (char*)pa_end; p += PGSIZE)
		freepage(p);
}

struct run {
	struct run *next;
}

struct {
	struct spinlock lock;
	struct run *freelist;
	uint64 npage;
}

void
kpminit()
{
	initlock(&kmem.lock, "kmem");
	kmem.freelist = 0;
	kmem.npage = 0;
	allocs = frees = 0;
	freerange(kernel_end, (void*)PHYSTOP);
	__debug_info("kpminit kernel_end: %p, phystop: %p, npage %d allocator:%p\n", kernel_end, (void*)PHYSTOP, kmem.npage,&kmem);
}

void
freepage(void *pa)
{
	struct run *r;

	if(((uint64)pa % PGSIZE) != 0 || (char*)pa < kernel_end || (uint64)pa >= PHYSTOP)
		panic("freepage");

	// Fill with junk to catch dangling refs.
	memset(pa, 1, PGSIZE);

	r = (struct run*)pa;

	acquire(&kmem.lock);
	r->next = kmem.freelist;
	kmem.freelist = r;
	kmem.npage++;
	frees++;
	release(&kmem.lock);
}

void *
allocpage(void)
{
	struct run *r;

	acquire(&kmem.lock);
	r = kmem.freelist;
	if (r) {
		kmem.freelist = r->next;
		kmem.npage--;
	}
	release(&kmem.lock);

	#ifdef DEBUG 
	if (r)
		memset((char*)r, 5, PGSIZE); // fill with junk
	#endif 

	allocs++;
	return (void*)r;
}

void
checkmemlist(void* pa){
	struct run* r = kmem.freelist;
	while(r){
	  if(pa == r){
	    __debug_warn("[freepage]free %p twice\n",pa);
	  }
	  r= r->next;
	}
}

