void
userinit()
{
  struct proc *p;

  p = allocproc(0, 0);
  if(firstuserinit){
    initproc = p;
    firstuserinit = 0;
  }
  else{
    allocparent(p,initproc);
    initproc = p;
  }
  alloc_load_vma(p, (uint64) 0, initcodesize, PTE_R|PTE_W|PTE_X|PTE_U);
  //print_vma_info(p);
  copyout(p->pagetable,0,initcode,initcodesize);


  p->trapframe->epc = 0x0;      // user program counter
  p->trapframe->sp = type_locate_vma(p->vma,STACK)->end;  // user stack pointer

  safestrcpy(p->name, "initcode", sizeof(p->name));

  p->state = RUNNABLE;
  readyq_push(p);//insert to ready queue
  p->tmask = 0;
  p->cwd = ename(NULL,"/",0);

  release(&p->lock);
  __debug_info("userinit\n");
}

int clone(uint64 flag, uint64 stack, uint64 ptid, uint64 tls, uint64 ctid) {
  int i, pid;
  struct proc *np;
  struct proc *p = myproc();

  if((flag & CLONE_THREAD) && (flag & CLONE_VM))
  {
    // Allocate process.
    if((np = allocproc(p, 1)) == NULL){
      return -1;
    }

    // copy saved user registers.
    *(np->trapframe) = *(p->trapframe);
    np->trapframe->tp = tls;
    np->trapframe->sp = stack;
    if(ptid != 0)
    {
      copyout(p->pagetable, ptid, (char *)&np->pid, sizeof(int));
    } 
  }
  else
  {
    //__debug_info("[clone]enter\n");
    // Allocate process.
    if((np = allocproc(p, 0)) == NULL){
      return -1;
    }
    // copy saved user registers.
    *(np->trapframe) = *(p->trapframe);
    if(stack != 0)
    {
      p->trapframe->sp = stack;
    }
  }

  // signal copy	
  sigaction_copy(&np->sig_act, p->sig_act);
  np->sig_frame = p->sig_frame;
  for (int i = 0; i < SIGSET_LEN; i++) {
    np->sig_pending.__val[i] = p->sig_pending.__val[i];
  }

  np->sz = p->sz;

  // copy tracing mask from parent.
  np->tmask = p->tmask;

  // Cause fork to return 0 in the child.
  np->trapframe->a0 = 0;


  // increment reference counts on open file descriptors.
  for(i = 0; i < NOFILE; i++)
    if(p->ofile[i])
      np->ofile[i] = filedup(p->ofile[i]);
  np->cwd = edup(p->cwd);

  // np->parent = p;
  allocparent(p, np);

  safestrcpy(np->name, p->name, sizeof(p->name));

  pid = np->pid;
  np->state = RUNNABLE;
  readyq_push(np);

  if(flag & CLONE_CHILD_SETTID){
    np->set_child_tid = ctid;

  }
  if(flag & CLONE_CHILD_CLEARTID){
    np->clear_child_tid = ctid;
  }

  p->killed = np->killed;


  release(&np->lock);
  //__debug_info("epc:%p\n",p->trapframe->epc);
  //__debug_info("[clone] successfully clone\n");
  return pid;
}

void
forkret(void)
{
  //printf("run in forkret\n");

  // Still holding p->lock from scheduler.
  release(&myproc()->lock);
  usertrapret();
}

uint64
procnum(void)
{
  int num = 0;
  struct proc *p;

  for (p = proc; p < &proc[NPROC]; p++) {
    if (p->state != UNUSED) {
      num++;
    }
  }

  return num;
}

void
sched(void)
{
  int intena;
  struct proc *p = myproc();

  if(!holding(&p->lock))
    panic("sched p->lock");
  if(mycpu()->noff != 1)
    panic("sched locks");
  if(p->state == RUNNING)
    panic("sched running");
  if(intr_get())
    panic("sched interruptible");

  intena = mycpu()->intena;
  swtch(&p->context, &mycpu()->context);
  mycpu()->intena = intena;
}

void
sleep(void *chan, struct spinlock *lk)
{
  struct proc *p = myproc();

  // Must acquire p->lock in order to
  // change p->state and then call sched.
  // Once we hold p->lock, we can be
  // guaranteed that we won't miss any wakeup
  // (wakeup locks p->lock),
  // so it's okay to release lk.
  if(lk != &p->lock){  //DOC: sleeplock0
    acquire(&p->lock);  //DOC: sleeplock1
    release(lk);
  }

  // Go to sleep.
  queue* q = findwaitq(chan);
  if(!q)q = allocwaitq(chan);
  if(!q){
    __debug_error("waitq pool is full\n");
  }
  waitq_push(q,p);
  p->state = SLEEPING;
  sched();

  // Tidy up.
  p->chan = 0;

  // Reacquire original lock.
  if(lk != &p->lock){
    release(&p->lock);
    acquire(lk);
  }
}

void
wakeup(void *chan)
{
   queue* q = findwaitq(chan);
   if(q){
     struct proc* p;
     while((p = waitq_pop(q))!=NULL){
       p->state = RUNNABLE;
       readyq_push(p);
     }
     delwaitq(q);
   }
}

void
allocparent(struct proc* parent,struct proc* child){
  child->parent = parent;
}

struct proc*
getparent(struct proc* child){
  return child->parent;
}

struct proc*
findchild(struct proc* p,int (*cond)(struct proc*,int),int pid,struct proc** child){
   *child = NULL;
   for(struct proc* np = proc; np < &proc[NPROC]; np++){
      // this code uses np->parent without holding np->lock.
      // acquiring the lock first would cause a deadlock,
      // since np might be an ancestor, and we already hold p->lock.
      if(np->parent == p&&cond(np,pid)){
        // np->parent can't change between the check and the acquire()
        // because only the parent changes it, and we're the parent.
        acquire(&np->lock);
        *child = np; 
        if(np->state == ZOMBIE){
          return np;
        }
        release(&np->lock);
      }
   }
   return NULL;
}

void
reparent(struct proc *p)
{
  struct proc *pp;

  for(pp = proc; pp < &proc[NPROC]; pp++){
    // this code uses pp->parent without holding pp->lock.
    // acquiring the lock first could cause a deadlock
    // if pp or a child of pp were also in exit()
    // and about to try to lock p.
    if(pp->parent == p){
      // pp->parent can't change between the check and the acquire()
      // because only the parent changes it, and we're the parent.
      acquire(&pp->lock);
      pp->parent = initproc;
      // we should wake up init here, but that would require
      // initproc->lock, which would be a deadlock, since we hold
      // the lock on one of init's children (pp). this is why
      // exit() always wakes init (before acquiring any locks).
      release(&pp->lock);
    }
  }
}

void
yield()
{
  struct proc *p = myproc();
  acquire(&p->lock);
  readyq_push(p);
  p->state = RUNNABLE;
  sched();
  release(&p->lock);
}

int zombiecond(struct proc* p,int pid){
  return (pid==-1||p->pid == pid);
}

int
wait4pid(int pid,uint64 addr)
{
  int kidpid;
  struct proc *p = myproc();
  struct proc* child;
  struct proc* chan = NULL;
  // hold p->lock for the whole time to avoid lost
  // wakeups from a child's exit().
  acquire(&p->lock);
  //__debug_warn("[wait4pid]pid%d:%s enter\n",p->pid,p->name);
  while(1){
    kidpid = pid;
    child = findchild(p,zombiecond,pid,&chan);
    //__debug_warn("[wait4pid]pid%d:%s chan:%p\n",p->pid,p->name,chan);
    if(child != NULL){
      kidpid = child->pid;
      p->proc_tms.cstime += child->proc_tms.stime + child->proc_tms.cstime;
      p->proc_tms.cutime += child->proc_tms.utime + child->proc_tms.cutime;
      child->xstate <<= 8;
      if(addr != 0 && copyout(p->pagetable, addr, (char *)&child->xstate, sizeof(child->xstate)) < 0) {
        release(&child->lock);
        release(&p->lock);
        __debug_warn("[wait4pid]pid%d:%s copyout bad\n",p->pid,p->name);
        return -1;
      }
      freeproc(child);
      release(&child->lock);
      release(&p->lock);
      //__debug_info("[wait4pid]pid%d:%s kidpid:%p\n",p->pid,p->name,kidpid);
      return kidpid;
    }
    if(!chan){
      //__debug_warn("[wait4pid]pid%d:%s no kid to wait\n",p->pid,p->name);
      release(&p->lock);
      return -1;
    }
    if(pid == -1)sleep(p, &p->lock);  //DOC: wait-sleep
    else sleep(chan,&p->lock);
  }
  release(&p->lock);
  return 0;
}

void
exit(int n)
{
  struct proc *p = myproc();
  //if(p == initproc)
    //panic("init exiting");
  //__debug_warn("[exit]pid %d:%s exit %d\n",p->pid,p->name,n);
  // Close all open files.
  for(int fd = 0; fd < NOFILE; fd++){
    if(p->ofile[fd]){
      struct file *f = p->ofile[fd];
      fileclose(f);
      p->ofile[fd] = 0;
    }
  }

  eput(p->cwd);
  p->cwd = 0;
  wakeup(p);
  acquire(&p->lock);
  wakeup(getparent(p));
  reparent(p);

  p->xstate = n;
  p->state = ZOMBIE;

  // p->killed = SIGTERM;
  // Jump into the scheduler, never to return.
  sched();
  panic("zombie exit");
  while(1){

  }
}

int kill(int pid,int sig){
	struct proc* p;
	for(p = proc; p < &proc[NPROC]; p++){
		if(p->pid == pid){
			acquire(&p->lock);
			if(p->state == SLEEPING){
				// need to modify...
				queue_del(p);
				readyq_push(p);
				p->state = RUNNABLE;
			}
			p->sig_pending.__val[0] |= 1ul << sig;
			if (0 == p->killed || sig < p->killed) {
				p->killed = sig;
			}
			release(&p->lock);
			return 0;
		}
	}
  //return -ESRCH;
  return 0;
}

static int cmp_parent(int pid,int sid){
  struct proc* p;
  for(p = proc;p < &proc[NPROC];p++){
    if(p->pid == sid) break;
  }
  while(p){
    p = getparent(p);
    if(!p)break;
    if(p->pid == pid) return 1;
  }
  return 0;
}

int tgkill(int pid,int tid,int sig){
  if(!cmp_parent(pid,tid)) return -1;
  else return kill(tid,sig);
}

