uint64 
sys_readv(void){
  int fd;
  struct file* f;
  uint64 iov;
  int iovcnt;
  int totlen = 0;
  if(argfd(0, &fd, &f) < 0)
  {
    return -1;
  }
  if(argaddr(1, &iov) < 0)
  {
    return -1;
  }
  if(argint(2, &iovcnt) < 0)
  {
    return -1;
  }
  struct proc* p = myproc();
  struct iovec v;
  //printf("[writev]fd:%d iov:%p iovcnt:%d\n",fd,iov,iovcnt);
  for(int i = 0;i<iovcnt;i++){
    uint64 vec = iov+i*sizeof(v);
    copyin(p->pagetable,(char*)&v,vec,sizeof(v));
    //printf("%d iov base:%p len:%p\n",i,v.iov_base,v.iov_len);
    if(!v.iov_len)continue;
    totlen += fileread(f,(uint64)v.iov_base,v.iov_len);
  }
  return totlen;
}

