  if(argfd(0, &olddirfd, &oldfp) < 0)
  {
    if(old[0] != '/' && olddirfd != AT_FDCWD)
    {
      return -EBADF;
    }
    olddp = p->cwd;
  }

  if(argfd(2, &newdirfd, &newfp) < 0)
  {
    if(new[0] != '/' && newdirfd != AT_FDCWD)
    {
      return -EBADF;
    }
    newdp = p->cwd;
  }

  // if(argint(4, &flags) < 0)
  // {
  //   return -ENAMETOOLONG;
  // }

  if ((src = ename(olddp, old, &olddevno)) == NULL || (pdst = enameparent(newdp, new, old, &newdevno)) == NULL
      || (name = formatname(old)) == NULL) {
    goto fail;          // src doesn't exist || dst parent doesn't exist || illegal new name
  }
  for (struct dirent *ep = pdst; ep != NULL; ep = ep->parent) {
    if (ep == src) {    // In what universe can we move a directory into its child?
      goto fail;
    }
  }

  uint off;
  elock(src);     // must hold child's lock before acquiring parent's, because we do so in other similar cases
  srclock = 1;
  elock(pdst);
  dst = dirlookup(pdst, name, &off);
  if (dst != NULL) {
    eunlock(pdst);
    if (src == dst) {
      goto fail;
    } else if (src->attribute & dst->attribute & ATTR_DIRECTORY) {
      elock(dst);
      if (!isdirempty(dst)) {    // it's ok to overwrite an empty dir
        eunlock(dst);
        goto fail;
      }
      elock(pdst);
    } else {                    // src is not a dir || dst exists and is not an dir
      goto fail;
    }
  }

  if (dst) {
    eremove(dst);
    eunlock(dst);
  }
  memmove(src->filename, name, FAT32_MAX_FILENAME);
  emake(pdst, src, off);
  if (src->parent != pdst) {
    eunlock(pdst);
    elock(src->parent);
  }
  eremove(src);
  eunlock(src->parent);
  struct dirent *psrc = src->parent;  // src must not be root, or it won't pass the for-loop test
  src->parent = edup(pdst);
  src->off = off;
  src->valid = 1;
  eunlock(src);

  eput(psrc);
  if (dst) {
    eput(dst);
  }
  eput(pdst);
  eput(src);

  return 0;

fail:
  if (srclock)
    eunlock(src);
  if (dst)
    eput(dst);
  if (pdst)
    eput(pdst);
  if (src)
    eput(src);
  return -1;

}

uint64
sys_ioctl(void)
{
	#define TIOCGWINSZ	0x5413
	#define TCGETS		0x5401

	struct winsize {
		uint16 ws_row;		/* rows， in character */
		uint16 ws_col; 		/* columns, in characters */
		uint16 ws_xpixel;	/* horizontal size, pixels (unused) */
		uint16 ws_ypixel;	/* vertical size, pixels (unused) */
	};

	#define ICRNL		0000400
	#define OPOST		0000001
	#define ONLCR		0000004
	#define ICANON		0000002
	#define ECHO		0000010


	struct termios {
		uint16 c_iflag; /* 输入模式标志*/
		uint16 c_oflag; /* 输出模式标志*/
		uint16 c_cflag; /* 控制模式标志*/
		uint16 c_lflag; /*区域模式标志或本地模式标志或局部模式*/
		uint8 c_line; /*行控制line discipline */
		uint8 c_cc[8]; /* 控制字符特性*/
	};

	int fd;
	struct file *f;
	uint64 request;
	uint64 argp;

	if (argfd(0, &fd, &f) < 0 || argaddr(1, &request) < 0 || argaddr(2, &argp) < 0)
		return -1;

	if (f->type != FD_DEVICE)
		return -1;

	switch (request) {
	case TIOCGWINSZ: {
		struct winsize win = {
			.ws_row = 24,
			.ws_col = 80,
		};
		if (copyout2(argp, (char*)&win, sizeof(win)) < 0)
			return -1;
		break;
	}
	case TCGETS: {
		struct termios terminfo = {
			.c_iflag = ICRNL,
			.c_oflag = OPOST|ONLCR,
			.c_cflag = 0,
			.c_lflag = ICANON|ECHO,
			.c_line = 0,
			.c_cc = {0},
		};
		if (copyout2(argp, (char*)&terminfo, sizeof(terminfo)) < 0)
			return -1;
		break;
	}
	default:
		return -1;
	}

	return 0;
}

uint64
sys_fcntl(void)
{
  int fd;
  int cmd;
  uint64 arg;
  struct file* f;
  struct proc* p = myproc();
  if(argfd(0, &fd, &f) < 0)
    return -1;
  if(argint(1, &cmd) < 0)
    return -1;
  if(argaddr(2, &arg) < 0)
    return -1;
   //printf("[sys fcntl]fd:%d cmd:%d arg:%p\n",fd,cmd,arg);
  if(cmd == F_GETFD){
    return p->exec_close[fd];
  }else if(cmd == F_SETFD){
    p->exec_close[fd] = arg;
  }else if(cmd == F_DUPFD){
    if((fd=fdallocfrom(f,arg)) < 0){
      return fd;
    }
    filedup(f);
    //__debug_warn("[sys fcntl]return fd:%d\n",fd);
    return fd;
  }else if(cmd == F_DUPFD_CLOEXEC){
    if((fd=fdallocfrom(f,arg)) < 0){
      return fd;
    }
    filedup(f);
    p->exec_close[fd] = 1;
    //__debug_warn("[sys fcntl]return fd:%d\n",fd);
    return fd;
  }
  return 0;
}

