static inline uint16_t i2c_min_clk_prescaler(unsigned int input_khz, unsigned int max_target_khz)
{
  // f_sck = f_in / (2 * (div + 1)) => div = (f_in / (2*f_sck)) - 1
  // prescale = (f_in / (5*f_scl)) - 1
  //
  // The nearest integer solution for div requires rounding up as to not exceed
  // max_target_khz.
  //
  // div = ceil(f_in / (5*f_scl)) - 1
  //     = floor((f_in - 1 + 5*f_scl) / (5*f_scl)) - 1
  //
  // This should not overflow as long as (f_in - 1 + 5*f_scl) does not exceed
  // 2^32 - 1, which is unlikely since we represent frequencies in kHz.
  unsigned int quotient = (input_khz + 5 * max_target_khz - 1) / (5 * max_target_khz);
  // Avoid underflow
  if (quotient == 0) {
    return 0;
  } else {
    return quotient - 1;
  }
}

static inline unsigned int uart_min_clk_divisor(uint64_t input_hz, uint64_t max_target_hz)
{
  // f_baud = f_in / (div + 1) => div = (f_in / f_baud) - 1
  // div = (f_in / f_baud) - 1
  //
  // The nearest integer solution for div requires rounding up as to not exceed
  // max_target_hz.
  //
  // div = ceil(f_in / f_baud) - 1
  //     = floor((f_in - 1 + f_baud) / f_baud) - 1
  //
  // This should not overflow as long as (f_in - 1 + f_baud) does not exceed
  // 2^32 - 1, which is unlikely since we represent frequencies in kHz.
  uint64_t quotient = (input_hz + max_target_hz - 1) / (max_target_hz);
  // Avoid underflow
  if (quotient == 0) {
    return 0;
  } else {
    return quotient - 1;
  }
}

static inline int ux00prci_select_corepll (
  volatile uint32_t *coreclkselreg,
  volatile uint32_t *corepllcfg,
  volatile uint32_t *corepllout,
  uint32_t pllconfigval)
{

  (*corepllcfg) = pllconfigval;

  // Wait for lock
  while (((*corepllcfg) & (PLL_LOCK(1))) == 0) ;

  uint32_t core_out =
    (PLLOUT_DIV(PLLOUT_DIV_default)) |
    (PLLOUT_DIV_BY_1(PLLOUT_DIV_BY_1_default)) |
    (PLLOUT_CLK_EN(1));
  (*corepllout) = core_out;

  // Set CORECLKSELREG to select COREPLL
  (*coreclkselreg) = PLL_CORECLKSEL_COREPLL;

  return 0;

}

